class Solution:
    def findMinHeight(self, arr: list[int], n: int) -> int:
        import heapq
        minHeap = []
        for i in arr:
            heapq.heappush(minHeap, i)
        height = 1
        while True:
            if len(minHeap) < height:
                return height
            if minHeap[0] > height:
                return height
            height *= 2

