class Solution {\
public:\
    int findMinHeight(int *arr, int n) {\
        priority_queue<int> minHeap;
        for (int i = 0; i < n; i++) {
            minHeap.push(arr[i]);
        }
        int height = 1;
        while (true) {
            if (minHeap.size() < height) {
                return height;
            }
            if (minHeap.top() > height) {
                return height;
            }
            height *= 2;
        }
    }
};
